function lectureToGradeCourse(lecture, index) {
  return {
    id: `timetable-${lecture.id}`,
    name: lecture.name,
    credit: lecture.credit ?? 3,
    professor: lecture.professor,
    totalClass: 15,
    hwTotal: 4,
  }
}

